-- 1. Swap the active flag atomically
BEGIN;
UPDATE embedding_config SET is_active = false WHERE version = 'v1';
UPDATE embedding_config SET is_active = true  WHERE version = 'v2';
COMMIT;

-- 2. Rename columns so queries use v2 automatically
ALTER TABLE document_chunks RENAME COLUMN embedding    TO embedding_v1_retired;
ALTER TABLE document_chunks RENAME COLUMN embedding_v2 TO embedding;

-- 3. Rebuild the HNSW index on the new column
DROP INDEX IF EXISTS document_chunks_embedding_idx;
CREATE INDEX CONCURRENTLY ON document_chunks
    USING hnsw (embedding vector_cosine_ops)
    WITH (m = 16, ef_construction = 64);

-- 4. Invalidate the application's cached config so it reloads v2
-- (restart workers or call cache_clear())

-- If v2 quality is worse: revert the active flag and rename columns back
BEGIN;
UPDATE embedding_config SET is_active = false WHERE version = 'v2';
UPDATE embedding_config SET is_active = true  WHERE version = 'v1';
COMMIT;

ALTER TABLE document_chunks RENAME COLUMN embedding           TO embedding_v2_retired;
ALTER TABLE document_chunks RENAME COLUMN embedding_v1_retired TO embedding;
-- Rebuild index on v1 column if you dropped it
CREATE INDEX CONCURRENTLY ON document_chunks
    USING hnsw (embedding vector_cosine_ops);
